import type { Product } from './types'
import { IMAGE_VIEWS, VIEW_CAPTIONS } from './imageManifest'

/**
 * 分类展签底色（无照片时的兜底），靠明度差区分分类，不靠色相。
 *
 * **为什么从深丝绒改成了纸色**：深色展签是 65 件商品、只有 5 件缺图那会儿定的，
 * 那时它是一片白里偶尔一块黑丝绒，克制而有戏。现在目录 1009 件、
 * 903 件（89%）没照片，于是四格里三格半是黑的——
 * 一个「真纸白 + 纯墨黑」的站，格子却成了黑白棋盘，深色反客为主。
 * 展签是占位，不该压过它占的那个位。
 * （深色仍然只属于：黑卡本卡、鉴定证书、照片上的浮层。）
 */
export const CATEGORY_GRADIENTS: Record<string, string> = {
  包袋皮具: 'bg-gradient-to-br from-neutral-100 to-neutral-200',
  腕表珠宝: 'bg-gradient-to-br from-zinc-100 to-zinc-200',
  尊贵座驾: 'bg-gradient-to-br from-neutral-200 to-neutral-300',
  游艇航空: 'bg-gradient-to-br from-slate-100 to-slate-200',
  不动产: 'bg-gradient-to-br from-stone-100 to-stone-200',
  科技算力: 'bg-gradient-to-br from-gray-200 to-gray-300',
  运动竞技: 'bg-gradient-to-br from-stone-200 to-neutral-200',
  酒窖餐桌: 'bg-gradient-to-br from-zinc-200 to-neutral-200',
  高定衣橱: 'bg-gradient-to-br from-zinc-100 to-stone-200',
  艺术收藏: 'bg-gradient-to-br from-neutral-100 to-zinc-200',
}

/** 品类英文显示名。内部键保持中文（与 product.category / bespoke 键一致），仅显示层用英文。 */
export const CATEGORY_LABELS: Record<string, string> = {
  包袋皮具: 'Bags & Leather',
  腕表珠宝: 'Watches & Jewellery',
  尊贵座驾: 'Motorcars',
  游艇航空: 'Yachts & Aviation',
  不动产: 'Real Estate',
  科技算力: 'Compute & Tech',
  运动竞技: 'Sport',
  酒窖餐桌: 'Cellar & Table',
  高定衣橱: 'Couture',
  艺术收藏: 'Art & Collectibles',
}

export function catLabel(cat: string): string {
  return CATEGORY_LABELS[cat] ?? cat
}

export const CATEGORIES = [
  { name: '包袋皮具', emoji: '👜' },
  { name: '腕表珠宝', emoji: '💎' },
  { name: '尊贵座驾', emoji: '🏎️' },
  { name: '游艇航空', emoji: '🛥️' },
  { name: '不动产', emoji: '🏝️' },
  { name: '科技算力', emoji: '🛰️' },
  { name: '运动竞技', emoji: '⛳' },
  { name: '酒窖餐桌', emoji: '🍷' },
  { name: '高定衣橱', emoji: '🕶️' },
  { name: '艺术收藏', emoji: '🖼️' },
].map((c) => ({ ...c, label: CATEGORY_LABELS[c.name] }))

function p(
  id: string,
  name: string,
  category: string,
  price: number,
  originalPrice: number,
  emoji: string,
  description: string,
  sales: string,
  easterEgg?: boolean,
): Product {
  return {
    id,
    name,
    category,
    price,
    originalPrice,
    emoji,
    gradient: CATEGORY_GRADIENTS[category],
    description,
    sales,
    easterEgg,
  }
}

/**
 * 一件藏品的全部图录视角（按顺序：全貌 / 另一角度 / 细节，随分类而定）。
 * 没有照片就返回空数组——那是常态，不是错误，交给丝绒展签兜底。
 *
 * 图有没有、有几张，是构建期就查清楚的事实（见 imageManifest.ts），
 * 不靠运行时 404 去试：1009 件里九成没图，靠试就是九百个必然失败的请求。
 */
export function viewsOf(product: Product): string[] {
  const n = IMAGE_VIEWS[product.id] ?? 0
  return Array.from({ length: n }, (_, i) => (i === 0 ? `/img/${product.id}.jpg` : `/img/${product.id}-v${i + 1}.jpg`))
}

/** 视角小字（图录腔）：Full view / Reverse / From above……按分类而定。 */
export function captionOf(product: Product, view: number): string {
  return VIEW_CAPTIONS[product.category]?.[view] ?? 'Further view'
}

