/**
 * 配货门槛：id → 需累计守住的额度。真实世界买热门铂金包/热门陀飞轮/超跑，
 * 都得先有购买记录（配货）才有资格——这里门槛按行情设为该款价格的数倍。
 * 本店的荒诞在于：配货本身也 ¥0.00，你反复花 ¥0.00 才换来花 ¥0.00 的资格。
 */
const QUOTA_RULES: Record<string, number> = {
  'lx-himalaya-croc': 8000000, // 喜马拉雅铂金包：全站最难配的一款
  'lx-croc-birkin': 2400000, // 鳄鱼铂金包：约 3.5 倍包价的配货
  'lx-ostrich-tote': 900000, // 鸵鸟皮包：入门级配货
  'lx-tourbillon-minute': 6000000, // 热门陀飞轮：需先配齐入门款
  'lx-daytona-steel': 1800000, // 钢款计时（新增热门款，先占位规则）
  'lx-nautilus-blue': 4500000, // 蓝盘运动钢表
  'lx-hyper-coupe': 30000000, // 限量超跑：凭历史订单排产
  'lx-f1-roadcar': 60000000, // 赛道量产车
}

export const PRODUCTS: Product[] = RAW_PRODUCTS.map((p) =>
  QUOTA_RULES[p.id] ? { ...p, quota: QUOTA_RULES[p.id] } : p,
)

export function getProduct(id: string): Product | undefined {
  return PRODUCTS.find((x) => x.id === id)
}

/** 私享区 SALON PRIVÉ：每个分类取最贵一件，一屏一物 */
export const SALON_PRODUCTS = CATEGORIES.map(
  (c) => PRODUCTS.filter((p) => p.category === c.name).sort((a, b) => b.price - a.price)[0],
).filter(Boolean)
